// Generated by Copilot. Sample for working with coroutines and IOCP in a simple echo server/client example using Winsock. 
// The code defines an IO event loop based on IOCP, custom awaitable types for asynchronous socket operations, and 
// demonstrates a server that accepts one client and echoes back messages, as well as a client that connects to the server 
// and sends messages. The main function allows running either the server or client based on command-line arguments.

#define WIN32_LEAN_AND_MEAN
#include <Windows.h>
#include <WinSock2.h>
#include <WS2tcpip.h>
#include <MSWSock.h>

import std;

#pragma comment(lib, "Ws2_32.lib")
#pragma comment(lib, "Mswsock.lib")

// ============================================================================
// Shared infrastructure: IOCP event loop + awaitable coroutine types
// ============================================================================
namespace Shared
{
	inline constexpr const char* Port = "27015";
	inline constexpr int BufferSize = 512;

	// RAII wrapper for WSAStartup / WSACleanup.
	struct WinsockScope
	{
		WinsockScope()
		{
			WSADATA d{};
			if (WSAStartup(MAKEWORD(2, 2), &d) != 0)
				throw std::runtime_error("WSAStartup failed");
		}
		~WinsockScope() { WSACleanup(); }
		WinsockScope(const WinsockScope&) = delete;
		WinsockScope& operator=(const WinsockScope&) = delete;
	};

	// Extended OVERLAPPED that carries the coroutine handle to resume.
	struct IoOperation : OVERLAPPED
	{
		std::coroutine_handle<> continuation{};
		DWORD bytesTransferred = 0;
		DWORD error = 0;
	};

	// A simple IOCP-based event loop that drives coroutines.
	class IoEventLoop
	{
	public:
		IoEventLoop()
		{
			m_iocp = CreateIoCompletionPort(INVALID_HANDLE_VALUE, nullptr, 0, 1);
			if (!m_iocp)
				throw std::runtime_error("CreateIoCompletionPort failed");
		}

		~IoEventLoop() { CloseHandle(m_iocp); }

		IoEventLoop(const IoEventLoop&) = delete;
		IoEventLoop& operator=(const IoEventLoop&) = delete;

		// Associate a socket with this IOCP.
		void Associate(SOCKET s)
		{
			if (!CreateIoCompletionPort(reinterpret_cast<HANDLE>(s), m_iocp, 0, 0))
				throw std::runtime_error("Failed to associate socket with IOCP");
		}

		// Post a manual completion (e.g. to wake the loop for a non-IO event).
		void Post(IoOperation* op)
		{
			PostQueuedCompletionStatus(m_iocp, 0, 0, op);
		}

		// Run the loop until there are no more outstanding operations.
		void Run()
		{
			while (m_outstandingOps > 0)
			{
				DWORD bytes = 0;
				ULONG_PTR key = 0;
				OVERLAPPED* overlapped = nullptr;

				BOOL ok = GetQueuedCompletionStatus(m_iocp, &bytes, &key, &overlapped, INFINITE);
				if (!overlapped)
					break;

				auto* op = static_cast<IoOperation*>(overlapped);
				op->bytesTransferred = bytes;
				op->error = ok ? 0 : GetLastError();

				if (op->continuation)
					op->continuation.resume();
			}
		}

		void AddOp() { ++m_outstandingOps; }
		void RemoveOp() { --m_outstandingOps; }

	private:
		HANDLE m_iocp = nullptr;
		int m_outstandingOps = 0;
	};

	// A coroutine return type that represents an async task producing a T.
	template <typename T = void>
	class Task;

	// Promise for Task<T> where T is non-void.
	template <typename T>
	struct TaskPromise
	{
		T result{};
		std::exception_ptr exception{};
		std::coroutine_handle<> continuation{};

		auto get_return_object() -> Task<T>;
		auto initial_suspend() noexcept -> std::suspend_always { return {}; }

		struct FinalAwaiter
		{
			auto await_ready() noexcept -> bool { return false; }
			auto await_suspend(std::coroutine_handle<TaskPromise> h) noexcept -> std::coroutine_handle<>
			{
				if (h.promise().continuation)
					return h.promise().continuation;
				return std::noop_coroutine();
			}
			void await_resume() noexcept {}
		};
		auto final_suspend() noexcept -> FinalAwaiter { return {}; }

		void return_value(T value) { result = std::move(value); }
		void unhandled_exception() { exception = std::current_exception(); }
	};

	// Promise specialisation for Task<void>.
	template <>
	struct TaskPromise<void>
	{
		std::exception_ptr exception{};
		std::coroutine_handle<> continuation{};

		auto get_return_object() -> Task<void>;
		auto initial_suspend() noexcept -> std::suspend_always { return {}; }

		struct FinalAwaiter
		{
			auto await_ready() noexcept -> bool { return false; }
			auto await_suspend(std::coroutine_handle<TaskPromise> h) noexcept -> std::coroutine_handle<>
			{
				if (h.promise().continuation)
					return h.promise().continuation;
				return std::noop_coroutine();
			}
			void await_resume() noexcept {}
		};
		auto final_suspend() noexcept -> FinalAwaiter { return {}; }

		void return_void() {}
		void unhandled_exception() { exception = std::current_exception(); }
	};

	template <typename T>
	class Task
	{
	public:
		using promise_type = TaskPromise<T>;

		explicit Task(std::coroutine_handle<promise_type> h) : m_handle(h) {}
		Task(Task&& other) noexcept : m_handle(std::exchange(other.m_handle, nullptr)) {}
		~Task() { if (m_handle) m_handle.destroy(); }

		Task(const Task&) = delete;
		Task& operator=(const Task&) = delete;

		// co_await support: when a coroutine co_awaits a Task, it suspends
		// and sets itself as the continuation so it resumes when the task completes.
		auto await_ready() const noexcept -> bool { return false; }

		auto await_suspend(std::coroutine_handle<> caller) noexcept -> std::coroutine_handle<>
		{
			m_handle.promise().continuation = caller;
			return m_handle; // symmetric transfer: start running this task
		}

		auto await_resume() -> T
		{
			if (m_handle.promise().exception)
				std::rethrow_exception(m_handle.promise().exception);
			if constexpr (!std::is_void_v<T>)
				return std::move(m_handle.promise().result);
		}

		// Start the coroutine without a caller (top-level).
		void Start() { m_handle.resume(); }

	private:
		std::coroutine_handle<promise_type> m_handle;
	};

	template <typename T>
	auto TaskPromise<T>::get_return_object() -> Task<T>
	{
		return Task<T>{ std::coroutine_handle<TaskPromise<T>>::from_promise(*this) };
	}

	inline auto TaskPromise<void>::get_return_object() -> Task<void>
	{
		return Task<void>{ std::coroutine_handle<TaskPromise<void>>::from_promise(*this) };
	}

	// Awaitable for an overlapped AcceptEx call.
	struct AcceptAwaitable
	{
		IoEventLoop& loop;
		SOCKET listenSocket;
		SOCKET acceptSocket = INVALID_SOCKET;
		IoOperation op{};
		char buffer[(sizeof(sockaddr_in) + 16) * 2]{};

		AcceptAwaitable(IoEventLoop& loop, SOCKET listenSocket)
			: loop(loop), listenSocket(listenSocket) {}

		auto await_ready() const noexcept -> bool { return false; }

		void await_suspend(std::coroutine_handle<> h)
		{
			op = {};
			op.continuation = h;

			acceptSocket = WSASocketW(AF_INET, SOCK_STREAM, IPPROTO_TCP, nullptr, 0, WSA_FLAG_OVERLAPPED);
			if (acceptSocket == INVALID_SOCKET)
				throw std::runtime_error("WSASocket failed for accept");

			loop.AddOp();
			DWORD bytes = 0;
			BOOL result = AcceptEx(
				listenSocket, acceptSocket,
				buffer, 0,
				sizeof(sockaddr_in) + 16, sizeof(sockaddr_in) + 16,
				&bytes, &op);

			if (!result && WSAGetLastError() != ERROR_IO_PENDING)
			{
				loop.RemoveOp();
				closesocket(acceptSocket);
				throw std::runtime_error("AcceptEx failed");
			}
		}

		auto await_resume() -> SOCKET
		{
			loop.RemoveOp();
			if (op.error != 0)
			{
				closesocket(acceptSocket);
				throw std::runtime_error("AcceptEx completion failed");
			}
			// Inherit listen socket properties so shutdown/getpeername work.
			setsockopt(acceptSocket, SOL_SOCKET, SO_UPDATE_ACCEPT_CONTEXT,
				reinterpret_cast<const char*>(&listenSocket), sizeof(listenSocket));
			return acceptSocket;
		}
	};

	// Awaitable for an overlapped WSARecv call.
	struct RecvAwaitable
	{
		IoEventLoop& loop;
		SOCKET socket;
		char* buffer;
		DWORD bufferLen;
		IoOperation op{};

		RecvAwaitable(IoEventLoop& loop, SOCKET s, char* buf, DWORD len)
			: loop(loop), socket(s), buffer(buf), bufferLen(len) {}

		auto await_ready() const noexcept -> bool { return false; }

		void await_suspend(std::coroutine_handle<> h)
		{
			op = {};
			op.continuation = h;

			WSABUF wsaBuf{ .len = bufferLen, .buf = buffer };
			DWORD flags = 0;
			loop.AddOp();
			int result = WSARecv(socket, &wsaBuf, 1, nullptr, &flags, &op, nullptr);
			if (result == SOCKET_ERROR && WSAGetLastError() != WSA_IO_PENDING)
			{
				loop.RemoveOp();
				throw std::runtime_error("WSARecv failed");
			}
		}

		auto await_resume() -> DWORD
		{
			loop.RemoveOp();
			return op.bytesTransferred;
		}
	};

	// Awaitable for an overlapped WSASend call.
	struct SendAwaitable
	{
		IoEventLoop& loop;
		SOCKET socket;
		const char* buffer;
		DWORD bufferLen;
		IoOperation op{};

		SendAwaitable(IoEventLoop& loop, SOCKET s, const char* buf, DWORD len)
			: loop(loop), socket(s), buffer(buf), bufferLen(len) {}

		auto await_ready() const noexcept -> bool { return false; }

		void await_suspend(std::coroutine_handle<> h)
		{
			op = {};
			op.continuation = h;

			WSABUF wsaBuf{ .len = bufferLen, .buf = const_cast<char*>(buffer) };
			DWORD flags = 0;
			loop.AddOp();
			int result = WSASend(socket, &wsaBuf, 1, nullptr, flags, &op, nullptr);
			if (result == SOCKET_ERROR && WSAGetLastError() != WSA_IO_PENDING)
			{
				loop.RemoveOp();
				throw std::runtime_error("WSASend failed");
			}
		}

		auto await_resume() -> DWORD
		{
			loop.RemoveOp();
			return op.bytesTransferred;
		}
	};

	// Awaitable for an overlapped ConnectEx call.
	struct ConnectAwaitable
	{
		IoEventLoop& loop;
		SOCKET socket;
		const sockaddr* addr;
		int addrLen;
		IoOperation op{};

		ConnectAwaitable(IoEventLoop& loop, SOCKET s, const sockaddr* a, int len)
			: loop(loop), socket(s), addr(a), addrLen(len) {}

		auto await_ready() const noexcept -> bool { return false; }

		void await_suspend(std::coroutine_handle<> h)
		{
			op = {};
			op.continuation = h;

			// Load ConnectEx via WSAIoctl (it's an extension function).
			LPFN_CONNECTEX connectEx = nullptr;
			GUID guid = WSAID_CONNECTEX;
			DWORD bytes = 0;
			WSAIoctl(socket, SIO_GET_EXTENSION_FUNCTION_POINTER,
				&guid, sizeof(guid), &connectEx, sizeof(connectEx), &bytes, nullptr, nullptr);
			if (!connectEx)
				throw std::runtime_error("Failed to load ConnectEx");

			loop.AddOp();
			BOOL result = connectEx(socket, addr, addrLen, nullptr, 0, nullptr, &op);
			if (!result && WSAGetLastError() != ERROR_IO_PENDING)
			{
				loop.RemoveOp();
				throw std::runtime_error("ConnectEx failed");
			}
		}

		void await_resume()
		{
			loop.RemoveOp();
			if (op.error != 0)
				throw std::runtime_error("ConnectEx completion failed");
			// Required for shutdown() etc. to work after ConnectEx.
			setsockopt(socket, SOL_SOCKET, SO_UPDATE_CONNECT_CONTEXT, nullptr, 0);
		}
	};
}

// ============================================================================
// Server: accepts one client, echoes back whatever it receives.
// ============================================================================
namespace Server
{
	using namespace Shared;

	auto CreateListenSocket(IoEventLoop& loop) -> SOCKET
	{
		addrinfo hints{};
		hints.ai_family = AF_INET;
		hints.ai_socktype = SOCK_STREAM;
		hints.ai_protocol = IPPROTO_TCP;
		hints.ai_flags = AI_PASSIVE;

		addrinfo* result = nullptr;
		if (getaddrinfo(nullptr, Port, &hints, &result) != 0)
			throw std::runtime_error("getaddrinfo failed");

		SOCKET s = WSASocketW(
			result->ai_family, result->ai_socktype, result->ai_protocol,
			nullptr, 0, WSA_FLAG_OVERLAPPED);
		if (s == INVALID_SOCKET)
		{
			freeaddrinfo(result);
			throw std::runtime_error("WSASocket failed");
		}

		if (bind(s, result->ai_addr, static_cast<int>(result->ai_addrlen)) == SOCKET_ERROR)
		{
			freeaddrinfo(result);
			closesocket(s);
			throw std::runtime_error("bind failed");
		}
		freeaddrinfo(result);

		if (listen(s, SOMAXCONN) == SOCKET_ERROR)
		{
			closesocket(s);
			throw std::runtime_error("listen failed");
		}

		loop.Associate(s);
		return s;
	}

	// Coroutine: handle a single client connection (echo loop).
	auto HandleClient(IoEventLoop& loop, SOCKET client) -> Task<>
	{
		loop.Associate(client);
		std::cout << "[Server] Client connected.\n";

		char buffer[BufferSize]{};
		while (true)
		{
			DWORD received = co_await RecvAwaitable(loop, client, buffer, BufferSize);
			if (received == 0)
			{
				std::cout << "[Server] Client disconnected.\n";
				break;
			}

			std::string_view msg(buffer, received);
			std::cout << "[Server] Received: " << msg << "\n";

			co_await SendAwaitable(loop, client, buffer, received);
			std::cout << "[Server] Echoed " << received << " bytes.\n";
		}

		closesocket(client);
	}

	// Coroutine: accept one client and handle it.
	auto AcceptAndServe(IoEventLoop& loop, SOCKET listenSocket) -> Task<>
	{
		std::cout << "[Server] Waiting for a client on port " << Port << "...\n";
		SOCKET client = co_await AcceptAwaitable(loop, listenSocket);
		co_await HandleClient(loop, client);
	}

	auto Run() -> int
	{
		try
		{
			WinsockScope wsa;
			IoEventLoop loop;
			SOCKET listenSocket = CreateListenSocket(loop);

			auto task = AcceptAndServe(loop, listenSocket);
			task.Start();
			loop.Run();

			closesocket(listenSocket);
			std::cout << "[Server] Done.\n";
		}
		catch (const std::exception& e)
		{
			std::cerr << "[Server] Error: " << e.what() << "\n";
			return 1;
		}
		return 0;
	}
}

// ============================================================================
// Client: connects to the server, sends messages, prints echoed replies.
// ============================================================================
namespace Client
{
	using namespace Shared;

	auto CreateConnectSocket(IoEventLoop& loop) -> SOCKET
	{
		SOCKET s = WSASocketW(AF_INET, SOCK_STREAM, IPPROTO_TCP, nullptr, 0, WSA_FLAG_OVERLAPPED);
		if (s == INVALID_SOCKET)
			throw std::runtime_error("WSASocket failed");

		// ConnectEx requires the socket to be bound first.
		sockaddr_in local{};
		local.sin_family = AF_INET;
		local.sin_addr.s_addr = INADDR_ANY;
		local.sin_port = 0;
		if (bind(s, reinterpret_cast<sockaddr*>(&local), sizeof(local)) == SOCKET_ERROR)
		{
			closesocket(s);
			throw std::runtime_error("bind failed for client socket");
		}

		loop.Associate(s);
		return s;
	}

	// Coroutine: connect to the server, send a few messages, read echoes.
	auto ConnectAndChat(IoEventLoop& loop) -> Task<>
	{
		SOCKET s = CreateConnectSocket(loop);

		addrinfo hints{};
		hints.ai_family = AF_INET;
		hints.ai_socktype = SOCK_STREAM;
		hints.ai_protocol = IPPROTO_TCP;

		addrinfo* result = nullptr;
		if (getaddrinfo("127.0.0.1", Port, &hints, &result) != 0)
			throw std::runtime_error("getaddrinfo failed");

		std::cout << "[Client] Connecting to 127.0.0.1:" << Port << "...\n";
		co_await ConnectAwaitable(loop, s, result->ai_addr, static_cast<int>(result->ai_addrlen));
		freeaddrinfo(result);
		std::cout << "[Client] Connected!\n";

		const char* messages[] = { "Hello", "from", "coroutines!" };
		char recvBuf[BufferSize]{};

		for (const char* msg : messages)
		{
			auto len = static_cast<DWORD>(std::strlen(msg));
			co_await SendAwaitable(loop, s, msg, len);
			std::cout << "[Client] Sent: " << msg << "\n";

			DWORD received = co_await RecvAwaitable(loop, s, recvBuf, BufferSize);
			std::string_view echo(recvBuf, received);
			std::cout << "[Client] Echo: " << echo << "\n";
		}

		shutdown(s, SD_SEND);
		closesocket(s);
		std::cout << "[Client] Done.\n";
	}

	auto Run() -> int
	{
		try
		{
			WinsockScope wsa;
			IoEventLoop loop;

			auto task = ConnectAndChat(loop);
			task.Start();
			loop.Run();
		}
		catch (const std::exception& e)
		{
			std::cerr << "[Client] Error: " << e.what() << "\n";
			return 1;
		}
		return 0;
	}
}

auto main(int argc, char* argv[]) -> int
{
	if (argc > 1 && std::string_view(argv[1]) == "--client")
		return Client::Run();

	// Default to server mode.
	return Server::Run();
}
